import { aboutUsList } from "../assets/aboutUsData";
import AboutSection from "./aboutUs/AboutSection";

export default function AboutUs() {
  return (
    <div>
      {aboutUsList.map((section, index) => (
        <AboutSection
          key = {index}
          section = {section}
        />
      ))}
    </div>
  )
}
